}
void write(ll x){
	if(x<0) putchar('-'),x=-x;
	if(x>=10) write(x/10);putchar(x%10+'0');
}
void writeln(ll x){write(x);puts("");}
void writep(ll x){write(x);putchar(' ');}

int n,cnt,ans,sum[13];
char a[103];

int main()
{
	while (cin>>a[++n]);
	int st=1;
	for (int i=1;i<=10;i++){
